const row = $json;
const num = (v) => parseFloat(String(v ?? '').replace(',', '.')) || 0;
let monto = num(row.monto ?? row.Monto ?? row.importe ?? row.Importe ?? row.valor ?? row.Valor);
const credito = num(row.credito ?? row.Credito ?? row.abono ?? row.Abono);
const debito = num(row.debito ?? row.Debito ?? row.cargo ?? row.Cargo);
if (!monto && (credito || debito)) monto = credito - debito;
const esIngreso = monto > 0;
const usuario_id = $('Director de Tráfico').first().json.usuario_id;
const origen = $('Director de Tráfico').first().json.origen;
return {
  json: {
    usuario_id,
    origen,
    monto: Math.abs(monto),
    categoria: 'Transaccion bancaria',
    entidad: row.descripcion ?? row.Descripcion ?? row.concepto ?? row.Concepto ?? row.entidad ?? 'Desconocido',
    fecha: row.fecha ?? row.Fecha ?? '',
    tipo: esIngreso ? 'INGRESO' : 'GASTO'
  }
};

const movimientos = $json.movimientos;
return {
  json: {
    usuario_id: movimientos[0].usuario_id,
    origen: movimientos[0].origen,
    accion: 'CARGA_MASIVA',
    movimientos: movimientos.map(m => ({
      monto: m.monto,
      categoria: m.categoria,
      entidad: m.entidad,
      fecha: m.fecha,
      tipo: m.tipo
    })),
    respuesta_chat: `He procesado correctamente los ${movimientos.length} movimientos de tu extracto bancario.`
  }
};

// Zona horaria fija (ajustar según país de tus usuarios; Colombia no tiene horario de verano)
const TZ_OFFSET_HOURS = -5; // America/Bogota

const baseMs = Number($json.timestamp_mensaje) || Date.now();
const localMs = baseMs + TZ_OFFSET_HOURS * 3600 * 1000;
const base = new Date(localMs);

function addDays(date, days) {
  const d = new Date(date);
  d.setUTCDate(d.getUTCDate() + days);
  return d;
}
function iso(date) {
  return date.toISOString().slice(0, 10);
}

const fechas = {
  hoy: iso(base),
  ayer: iso(addDays(base, -1)),
  antier: iso(addDays(base, -2)),
  anteayer: iso(addDays(base, -2)),
  manana: iso(addDays(base, 1)),
  pasado_manana: iso(addDays(base, 2)),
  hace_2_dias: iso(addDays(base, -2)),
  hace_3_dias: iso(addDays(base, -3)),
  hace_una_semana: iso(addDays(base, -7)),
  hace_2_semanas: iso(addDays(base, -14))
};

return {
  json: {
    ...$json,
    fechas_referencia: fechas
  }
};

// 1. Obtenemos la salida en texto generada por el Agente de IA
let raw = $json.output ?? '';
if (typeof raw !== 'string') raw = JSON.stringify(raw);

// 2. Extraemos el PRIMER objeto JSON balanceado (contando llaves), ignorando
//    cualquier basura que el modelo agregue después (ej. intentos fallidos de
//    tool-calling en texto plano tipo <function=...>{...}</function> que
//    algunos modelos como llama-3.1-8b-instant a veces generan).
function extraerPrimerJSON(texto) {
  const inicio = texto.indexOf('{');
  if (inicio === -1) return null;
  let profundidad = 0;
  for (let i = inicio; i < texto.length; i++) {
    if (texto[i] === '{') profundidad++;
    else if (texto[i] === '}') {
      profundidad--;
      if (profundidad === 0) return texto.slice(inicio, i + 1);
    }
  }
  return null; // nunca se cerró correctamente
}

const bloqueJson = extraerPrimerJSON(raw);

let parsed;
try {
  parsed = JSON.parse(bloqueJson);
} catch (e) {
  parsed = { accion: 'OTRO', datos: {}, respuesta_chat: 'No pude entender tu mensaje, ¿puedes reformularlo?' };
}

// 3. Recuperamos las variables de contexto
const usuario_id = $('Director de Tráfico').item.json.usuario_id;
const origen = $('Director de Tráfico').item.json.origen;
const accion = parsed.accion || 'OTRO';

const ACCIONES_TRANSACCIONALES = ['GASTO', 'INGRESO', 'CARGA_MASIVA'];

// 4a. Si es una transacción (individual o carga masiva), mantenemos el contrato
//     ya validado con el backend: usuario_id, origen, accion, movimientos[], respuesta_chat
if (ACCIONES_TRANSACCIONALES.includes(accion)) {
  let movimientosArray = [];
  if (accion === 'CARGA_MASIVA') {
    movimientosArray = Array.isArray(parsed.datos) ? parsed.datos : [];
  } else if (parsed.datos && typeof parsed.datos === 'object' && Object.keys(parsed.datos).length > 0) {
    movimientosArray = [parsed.datos];
  }

  // Backfill defensivo: si el modelo omitió "tipo" en algún movimiento, lo inferimos
  // usando la acción original como pista (GASTO por defecto si no se puede determinar)
  const tipoPorAccion = { GASTO: 'GASTO', INGRESO: 'INGRESO' };
  movimientosArray = movimientosArray.map(m => ({
    ...m,
    tipo: m.tipo || tipoPorAccion[accion] || 'GASTO'
  }));

  return {
    json: {
      usuario_id,
      origen,
      accion,
      // total_registros SIEMPRE se recalcula del array real, nunca se confía en lo
      // que el modelo haya dicho (puede desincronizarse, como pasó aquí: dijo 9, había 8).
      total_registros: movimientosArray.length,
      movimientos: movimientosArray,
      respuesta_chat: parsed.respuesta_chat || 'Operación procesada correctamente.'
    }
  };
}

// 4b. Para el resto de acciones (CREAR_PRESUPUESTO, CONSULTAR_PRESUPUESTO, FAQ, TICKET,
//     CONFIRMACION, OTRO) no aplica la forma "movimientos" — usamos "datos" tal cual,
//     ya que cada una tiene su propia forma según RF-03/RF-05.
return {
  json: {
    usuario_id,
    origen,
    accion,
    datos: parsed.datos || {},
    respuesta_chat: parsed.respuesta_chat || 'Operación procesada correctamente.'
  }
};

return {
  json: {
    usuario_id: $json.usuario_id,
    origen: $json.origen,
    accion: 'OTRO',
    datos: {},
    respuesta_chat: 'Por ahora no puedo leer imágenes 📷. Si quieres que registre movimientos desde tu banco, envíame el extracto como archivo .csv 📄, o cuéntame el gasto/ingreso en un mensaje de texto.'
  }
};

// Clasificador determinístico de categorías por palabras clave.
// No usa IA: es rápido, gratis, y garantiza que SIEMPRE caiga en una de las categorías fijas.

const KEYWORDS_GASTO = {
  'Comida': ['comida', 'restaurante', 'almuerzo', 'cena', 'desayuno', 'cafe', 'café', 'cafeteria', 'cafetería', 'supermercado', 'mercado', 'snack', 'bebida', 'pizza', 'pollo', 'hamburguesa', 'panaderia', 'panadería'],
  'Educacion': ['educacion', 'educación', 'universidad', 'colegio', 'curso', 'libro', 'matricula', 'matrícula', 'colegiatura', 'capacitacion', 'capacitación', 'escuela', 'clases'],
  'Entretenimiento': ['entretenimiento', 'cine', 'streaming', 'netflix', 'juego', 'concierto', 'fiesta', 'bar', 'diversion', 'diversión', 'spotify', 'disney', 'videojuego'],
  'Salud': ['salud', 'farmacia', 'medico', 'médico', 'doctor', 'hospital', 'medicina', 'consulta', 'clinica', 'clínica', 'seguro medico', 'seguro médico', 'dentista'],
  'Servicios': ['servicio', 'luz', 'agua', 'internet', 'telefono', 'teléfono', 'electricidad', 'gas', 'arriendo', 'alquiler', 'renta', 'suscripcion', 'suscripción'],
  'Transporte': ['transporte', 'bus', 'taxi', 'uber', 'gasolina', 'combustible', 'parqueo', 'peaje', 'metro', 'pasaje', 'bencina']
};

const CATEGORIAS_GASTO_VALIDAS = ['Comida', 'Educacion', 'Entretenimiento', 'Salud', 'Servicios', 'Transporte', 'Otros'];
const CATEGORIAS_INGRESO_VALIDAS = ['Salario', 'Venta', 'Regalo', 'Otros'];

function clasificarGasto(categoriaOriginal, entidad) {
  // Si el modelo ya devolvió exactamente una categoría válida, respétala
  const directo = CATEGORIAS_GASTO_VALIDAS.find(c => c.toLowerCase() === String(categoriaOriginal || '').toLowerCase());
  if (directo) return directo;

  const texto = `${categoriaOriginal || ''} ${entidad || ''}`.toLowerCase();
  for (const [categoria, palabras] of Object.entries(KEYWORDS_GASTO)) {
    if (palabras.some(p => texto.includes(p))) return categoria;
  }
  return 'Otros';
}

function clasificarIngreso(categoriaOriginal, entidad) {
  const directo = CATEGORIAS_INGRESO_VALIDAS.find(c => c.toLowerCase() === String(categoriaOriginal || '').toLowerCase());
  if (directo) return directo;

  const texto = `${categoriaOriginal || ''} ${entidad || ''}`.toLowerCase();
  if (texto.includes('salario') || texto.includes('sueldo') || texto.includes('nomina') || texto.includes('nómina') || texto.includes('quincena')) return 'Salario';
  if (texto.includes('venta') || texto.includes('vendi') || texto.includes('vendí')) return 'Venta';
  if (texto.includes('regalo') || texto.includes('obsequio') || texto.includes('me regalaron') || texto.includes('cumpleaños') || texto.includes('herencia')) return 'Regalo';
  return 'Otros';
}

// Solo aplica si este item tiene "movimientos" (transacciones); el resto de acciones
// (CREAR_PRESUPUESTO, CONSULTAR_PRESUPUESTO, FAQ, TICKET, CONFIRMACION, OTRO) pasan sin tocar.
if (Array.isArray($json.movimientos)) {
  const movimientos = $json.movimientos.map(m => ({
    ...m,
    categoria: m.tipo === 'INGRESO' ? clasificarIngreso(m.categoria, m.entidad) : clasificarGasto(m.categoria, m.entidad)
  }));
  return { json: { ...$json, movimientos } };
}

return { json: $json };

// Un item por cada pregunta/respuesta — así cada una se guarda como un documento
// independiente en el vector store, lo que da mejor precisión en la búsqueda.
const faqs = [
  { pregunta: "¿Cómo borro un gasto?", respuesta: "Ve a la sección 'Historial' en la app web, desliza la transacción y presiona el ícono de papelera." },
  { pregunta: "¿Kinti es gratis?", respuesta: "Sí, la versión básica de Kinti es 100% gratuita." },
  { pregunta: "¿Cuáles son las categorías de presupuesto?", respuesta: "Las categorías disponibles son: Comida, Educación, Entretenimiento, Salud, Servicios, Transporte y Otros." },
  { pregunta: "¿Cómo funcionan las alertas de presupuesto?", respuesta: "Te avisaremos por este medio cuando superes el 80% (umbral por defecto) de tu presupuesto en una categoría." },
  { pregunta: "¿Cómo cambio mi moneda predeterminada?", respuesta: "Ve a tu Perfil en la app web y selecciona la moneda que prefieras (USD, EUR, CLP, etc.)." },
  { pregunta: "¿Cómo registro un gasto por Telegram?", respuesta: "Solo escríbeme en lenguaje natural, por ejemplo 'gasté 20 en comida', y yo lo interpreto automáticamente." },
  { pregunta: "¿Puedo subir un extracto bancario?", respuesta: "Sí, desde la app web puedes subir tu extracto bancario en formato .csv y lo proceso automáticamente." },
  { pregunta: "¿Cómo edito un presupuesto ya creado?", respuesta: "Dime el nuevo monto para esa categoría y lo actualizo, o hazlo desde la sección Presupuestos en la app web." },
  { pregunta: "¿Puedo registrar varios gastos en un solo mensaje?", respuesta: "Sí, puedes describir varios movimientos en un mismo mensaje (por ejemplo 'gasté 20 en comida y 30 en transporte') y los registro todos juntos." },
  { pregunta: "¿Qué formatos de archivo acepta Kinti?", respuesta: "Por ahora solo proceso archivos .csv de extractos bancarios. No puedo leer imágenes ni otros formatos todavía." }
];

return faqs.map(f => ({
  json: { text: `Pregunta: ${f.pregunta}\nRespuesta: ${f.respuesta}` }
}));

function generarUUID() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function (c) {
    const r = (Math.random() * 16) | 0;
    const v = c === 'x' ? r : (r & 0x3) | 0x8;
    return v.toString(16);
  });
}

const PRIORIDAD_MAP = { ALTA: 'alta', MEDIA: 'media', BAJA: 'baja' };

const mensajeOriginal = $('Director de Tráfico').item.json.mensaje || '';

return {
  json: {
    id: generarUUID(),
    userId: $json.usuario_id,
    subject: ($json.datos && $json.datos.asunto) || 'Sin asunto especificado',
    priority: PRIORIDAD_MAP[($json.datos && $json.datos.prioridad) || ''] || 'media',
    status: 'abierto',
    context: mensajeOriginal,
    createdAt: new Date().toISOString()
  }
};
